# Package ecosystem -> cache environment variable exports
# Format: ecosystem_pattern<TAB>export_line
# ecosystem_pattern is matched against install_id or pkg_path in IR INSTALL records
# Multiple lines per ecosystem are emitted in order

python	export UV_CACHE_DIR="$FLOX_ENV_CACHE/uv"
python	export PIP_CACHE_DIR="$FLOX_ENV_CACHE/pip"
nodejs	export npm_config_cache="$FLOX_ENV_CACHE/npm"
rust	export CARGO_HOME="$FLOX_ENV_CACHE/cargo"
go	export GOPATH="$FLOX_ENV_CACHE/go"
go	export GOMODCACHE="$FLOX_ENV_CACHE/go/pkg/mod"
yarn	export YARN_CACHE_FOLDER="$FLOX_ENV_CACHE/yarn"
pnpm	export PNPM_STORE_PATH="$FLOX_ENV_CACHE/pnpm-store"
ruby	export GEM_HOME="$FLOX_ENV_CACHE/gems"
bundler	export BUNDLE_PATH="$FLOX_ENV_CACHE/bundle"
composer	export COMPOSER_CACHE_DIR="$FLOX_ENV_CACHE/composer"
maven	export MAVEN_USER_HOME="$FLOX_ENV_CACHE/maven"
gradle	export GRADLE_USER_HOME="$FLOX_ENV_CACHE/gradle"
